import * as Y from "yjs";

//#region src/y-zustand.ts
let isSyncingFromYjs = false;
/**
* A function to recursively convert plain JavaScript objects and arrays into Yjs types.
*/
function jsToY(value) {
	if (typeof value !== "object" || value === null) return value;
	if (Array.isArray(value)) return Y.Array.from(value.map(jsToY));
	const ymap = new Y.Map();
	for (const [key, val] of Object.entries(value)) ymap.set(key, jsToY(val));
	return ymap;
}
const syncYjsMiddleware = (doc, name, options = {}) => (creator) => {
	const ymap = doc.getMap(name);
	const { partialize = (state) => state } = options;
	return (set, get, api) => {
		const observer = () => {
			isSyncingFromYjs = true;
			set(ymap.toJSON());
			isSyncingFromYjs = false;
		};
		ymap.observeDeep(observer);
		api.subscribe((state, prevState) => {
			if (isSyncingFromYjs) return;
			const partialState = partialize(state);
			const partialPrevState = partialize(prevState);
			doc.transact(() => {
				Object.entries(partialState).forEach(([key, value]) => {
					if (typeof value === "function") return;
					const prevValue = partialPrevState[key];
					if (JSON.stringify(value) !== JSON.stringify(prevValue)) ymap.set(key, jsToY(value));
				});
			});
		});
		const initialStateFromCreator = creator(set, get, api);
		if (ymap.size === 0) {
			doc.transact(() => {
				const partialState = partialize(initialStateFromCreator);
				for (const key in partialState) {
					const value = partialState[key];
					if (typeof value !== "function") ymap.set(key, jsToY(value));
				}
			});
			return initialStateFromCreator;
		} else {
			const stateFromYjs = ymap.toJSON();
			const mergedState = {
				...initialStateFromCreator,
				...stateFromYjs
			};
			return mergedState;
		}
	};
};

//#endregion
export { syncYjsMiddleware };